def find_max_sum(arr):
    max_sum = 0
    left = 0
    right = len(arr) - 1
    while left < right:
        if arr[left] + arr[right] > max_sum:
            max_sum = arr[left] + arr[right]
        if arr[left] > arr[right]:
            right -= 1
        else:
            left += 1
    return max_sum

